from typing import Optional, List
import heapq
from collections import defaultdict

# Si = Si - 1 + "1" + reverse(invert(Si - 1))


class Solution:
    def findKthBit(self, n: int, k: int) -> str:
        def rev(s: str) -> str:
            result = ""
            for ch in s:
                if ch == "0":
                    result = "1" + result
                else:
                    result = "0" + result
            return result

        s = {
            0: "0",
            1: "011",
            2: "0111001",
            3: "011100110110001",
            4: "0111001101100011011100100110001",
            5: "011100110110001101110010011000110111001101100010011100100110001",
            6: "0111001101100011011100100110001101110011011000100111001001100011011100110110001101110010011000100111001101100010011100100110001",
            7: "011100110110001101110010011000110111001101100010011100100110001101110011011000110111001001100010011100110110001001110010011000110111001101100011011100100110001101110011011000100111001001100010011100110110001101110010011000100111001101100010011100100110001",
            8: "",
            9: "",
            10: "",
            11: "",
            12: "",
        }

        def rec(i):
            if i in s:
                return s[i]
            prev = rec(i - 1)
            s[i] = prev + "1" + rev(prev)
            return s[i]

        tmp = rec(n - 1)
        return tmp[k - 1]


if __name__ == "__main__":
    sol = Solution()
    print(sol.findKthBit(20, 1))
    print("Running Solution...")
